SELECT DISTINCT s.state_id
FROM states s
INNER JOIN representative_state rs ON s.state_id = rs.state_id;

SELECT COUNT(representative_id) 
FROM representative_terms 
WHERE term = 1;

SELECT COUNT(vote_id) AS passed_votes_count
FROM vote_outcomes
WHERE outcome = 'passed';

SELECT representative_id, term, start_date
FROM representative_terms
WHERE start_date LIKE '2020%';

SELECT user_id, permission, COUNT(permission) AS permission_count
FROM user_permissions
GROUP BY user_id, permission;

SELECT COUNT(representative_id) 
FROM representative_committees 
WHERE committee_id = 1;

SELECT committee_name
FROM committees
WHERE committee_id = 0;

SELECT representative_id
FROM representative_committees
WHERE committee_id = 1;

SELECT permission, 'active' AS status
FROM user_permissions
WHERE user_id = 1;

SELECT COUNT(DISTINCT committee_id) AS total_committees_chaired
FROM committee_chairs
WHERE representative_id = 0;

SELECT start_date
FROM representative_terms
WHERE representative_id = 1;

SELECT abbreviation
FROM states
ORDER BY abbreviation;
